      eventName: MobileEventNames.joinCallableLatency,
      durationMs: stopwatch.elapsedMilliseconds,
      attributes: const <String, Object?>{
        'result': 'success',
      },
    );
  } on FirebaseFunctionsException catch (error) {
    if (!context.mounted) {
      return;
    }
    _mobileTelemetry.track(
      eventName: MobileEventNames.routeJoin,
      category: 'join',
      addBreadcrumb: true,
      attributes: <String, Object?>{
        'result': 'error',
        'code': error.code,
      },
    );
    _mobileTelemetry.trackPerf(
      eventName: MobileEventNames.joinCallableLatency,
      durationMs: stopwatch.elapsedMilliseconds,
      attributes: <String, Object?>{
        'result': 'error',
        'code': error.code,
      },
    );
    final failurePlan = _planPassengerJoinFailureHandlingUseCase.execute(
      PlanPassengerJoinFailureHandlingCommand.functionsFailure(
        isQrEntry: source == _JoinEntrySource.qr,
        errorCode: error.code,
        errorMessage: error.message,
      ),
    );
    if (failurePlan.action ==
        PassengerJoinFailureHandlingAction.navigateToJoinErrorRoute) {
      context.go(
        _buildJoinErrorRoute(
          role: JoinRole.passenger,
          reason: failurePlan.joinErrorReason ?? _joinErrorUnknown,
        ),
      );
    } else {
      _showInfo(context, failurePlan.feedbackMessage!);
    }
  } catch (_) {
    if (!context.mounted) {
      return;
    }
    final failurePlan = _planPassengerJoinFailureHandlingUseCase.execute(
      PlanPassengerJoinFailureHandlingCommand.unknownFailure(
        isQrEntry: source == _JoinEntrySource.qr,
      ),
    );
    if (failurePlan.action ==
        PassengerJoinFailureHandlingAction.navigateToJoinErrorRoute) {
      context.go(
        _buildJoinErrorRoute(
          role: JoinRole.passenger,
          reason: failurePlan.joinErrorReason ?? _joinErrorUnknown,
        ),
      );
    } else {
      _showInfo(context, failurePlan.feedbackMessage!);
    }
  }
}

