      context.push(trackingUri.toString());
    }
    _mobileTelemetry.track(
      eventName: MobileEventNames.routeJoin,
      category: 'join',
      addBreadcrumb: true,
      attributes: <String, Object?>{
        'result': 'success',
        'role': 'guest',
        'routeId': routeId,
      },
    );
    _mobileTelemetry.trackPerf(
      eventName: MobileEventNames.joinCallableLatency,
      durationMs: stopwatch.elapsedMilliseconds,
      attributes: const <String, Object?>{
        'result': 'success',
        'role': 'guest',
      },
    );
  } on FirebaseFunctionsException catch (error) {
    if (!context.mounted) {
      return;
    }
    _mobileTelemetry.track(
      eventName: MobileEventNames.routeJoin,
      category: 'join',
      addBreadcrumb: true,
      attributes: <String, Object?>{
        'result': 'error',
        'role': 'guest',
        'code': error.code,
      },
    );
    _mobileTelemetry.trackPerf(
      eventName: MobileEventNames.joinCallableLatency,
      durationMs: stopwatch.elapsedMilliseconds,
      attributes: <String, Object?>{
        'result': 'error',
        'role': 'guest',
        'code': error.code,
      },
    );
    final failurePlan = _planGuestSessionCreateFailureHandlingUseCase.execute(
      PlanGuestSessionCreateFailureHandlingCommand.functionsFailure(
        isQrEntry: source == _JoinEntrySource.qr,
        errorCode: error.code,
      ),
    );
    if (failurePlan.action ==
        GuestSessionCreateFailureHandlingAction.navigateToJoinErrorRoute) {
      context.go(
        _buildJoinErrorRoute(
          role: JoinRole.guest,
          reason: failurePlan.joinErrorReason ?? _joinErrorUnknown,
        ),
      );
    } else {
      _showInfo(context, failurePlan.feedbackMessage!);
    }
  } catch (_) {
    if (!context.mounted) {
      return;
    }
    final failurePlan = _planGuestSessionCreateFailureHandlingUseCase.execute(
      PlanGuestSessionCreateFailureHandlingCommand.unknownFailure(
        isQrEntry: source == _JoinEntrySource.qr,
      ),
    );
    if (failurePlan.action ==
        GuestSessionCreateFailureHandlingAction.navigateToJoinErrorRoute) {
      context.go(
        _buildJoinErrorRoute(
          role: JoinRole.guest,
          reason: failurePlan.joinErrorReason ?? _joinErrorUnknown,
        ),
      );
    } else {
      _showInfo(context, failurePlan.feedbackMessage!);
    }
  }
}

Future<bool> _ensureAnonymousSessionForGuestFlow(BuildContext context) async {
  final currentUser = _authCredentialGateway.currentUser;
  if (currentUser != null && currentUser.isAnonymous) {
    return true;
  }

  try {
    if (currentUser != null && !currentUser.isAnonymous) {
      await _clearSessionRolePreference();
      await _clearCachedPassengerRoute();
      await _driverPushTokenRegistrationService.dispose();
      await _authCredentialGateway.signOut();
    }
    await _authCredentialGateway.signInAnonymously();
  } on FirebaseAuthException catch (error) {
    if (context.mounted) {
      final message = _resolveAnonymousSignInFailureFeedbackMessageUseCase
          .execute(errorCode: error.code);
      _showInfo(context, message);
    }
    return false;
  } catch (_) {
    if (context.mounted) {
      _showInfo(
        context,
        _resolveAnonymousSignInFailureFeedbackMessageUseCase.execute(
          errorCode: null,
        ),
      );
    }
    return false;
  }

  try {
    await _bootstrapCurrentProfile();
  } catch (_) {
    // Guest join flow can continue even if bootstrap metadata call fails.
  }

  return true;
}
